import { useState, useEffect, useCallback } from 'react';
import Dashboard from './components/Dashboard';
import ChatSession from './components/ChatSession';
import LoginPage from './components/LoginPage';
import { useMasteryStore } from './store/masteryStore';
import { useAuthStore } from './store/authStore';

export default function App() {
  const { user, loading } = useAuthStore();
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [pendingPrompt, setPendingPrompt] = useState<string | null>(null);

  // Req 8: Default to true — sandbox mode is on unless the user explicitly turned it off.
  const [isSandboxMode, setIsSandboxMode] = useState<boolean>(
    () => localStorage.getItem('tp_sandbox_mode') !== 'false'
  );

  useEffect(() => {
    localStorage.setItem('tp_sandbox_mode', String(isSandboxMode));
  }, [isSandboxMode]);

  useEffect(() => {
    if (!user) return;

    let unsubscribe: any;
    const setupSync = async () => {
      unsubscribe = await useMasteryStore.getState().syncFromCloud(
        user.uid, 
        user.displayName || undefined,
        user.photoURL || undefined
      );
    };

    setupSync();
    return () => { if (typeof unsubscribe === 'function') unsubscribe(); };
  }, [user]);

  const handleAskLina = useCallback((prompt: string) => {
    setPendingPrompt(prompt);
    setIsChatOpen(true);
  }, []);

  const handleClearPrompt = useCallback(() => setPendingPrompt(null), []);
  const handleEndSession = useCallback(() => setIsChatOpen(false), []);
  const handleStartSession = useCallback(() => setIsChatOpen(true), []);

  if (loading) {
    return (
      <div style={{ 
        height: '100dvh', 
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'center', 
        background: 'var(--bg)', 
        color: 'var(--text)' 
      }}>
        <div style={{ fontWeight: 900, letterSpacing: '0.1em' }}>TENPO PONA...</div>
      </div>
    );
  }

  if (!user) {
    return <LoginPage />;
  }

  return (
    <>
      <Dashboard
        onStartSession={handleStartSession}
        onAskLina={handleAskLina}
        isSandboxMode={isSandboxMode}
        setIsSandboxMode={setIsSandboxMode}
      />
      <ChatSession
        isActive={isChatOpen}
        onEndSession={handleEndSession}
        pendingPrompt={pendingPrompt}
        clearPrompt={handleClearPrompt}
        isSandboxMode={isSandboxMode}
      />
    </>
  );
}

import { create } from 'zustand';
import { auth, googleProvider } from '../services/firebase';
import { 
  signInWithPopup, 
  signInWithRedirect, 
  getRedirectResult, 
  signOut, 
  onAuthStateChanged, 
  type User 
} from 'firebase/auth';

interface AuthState {
  user: User | null;
  isGuest: boolean;
  loading: boolean;
  error: string | null;
  signIn: () => Promise<void>;
  skipSignIn: () => void;
  logout: () => Promise<void>;
  setUser: (user: User | null) => void;
}

export const useAuthStore = create<AuthState>((set) => ({
  user: null,
  isGuest: false,
  loading: true,
  error: null,
  signIn: async () => {
    set({ loading: true, error: null });
    try {
      console.log('Attempting sign-in with popup...');
      await signInWithPopup(auth, googleProvider);
    } catch (error: any) {
      console.error('Sign-in popup failed:', error.code, error.message);

      // Fallback for Chromebooks/blocked popups
      if (
        error.code === 'auth/popup-blocked' || 
        error.code === 'auth/popup-closed-by-user' || 
        error.code === 'auth/cancelled-popup-request'
      ) {
        console.log('Switching to redirect mode...');
        try {
          await signInWithRedirect(auth, googleProvider);
        } catch (redirectError: any) {
          console.error('Sign-in redirect failed:', redirectError.code);
          set({ error: redirectError.message, loading: false });
        }
      } else {
        set({ error: error.message, loading: false });
      }
    }
  },
  skipSignIn: () => {
    const guestUser = {
      uid: 'guest_user',
      displayName: 'Guest Student',
      photoURL: null,
    } as User;
    set({ user: guestUser, isGuest: true, loading: false });
  },
  logout: async () => {
    try {
      await signOut(auth);
      set({ user: null, isGuest: false });
    } catch (error) {
      console.error('Error signing out:', error);
    }
  },
  setUser: (user) => set({ user, loading: false }),
}));

// Handle redirect result on initialization
getRedirectResult(auth).catch((error) => {
  console.error('Error getting redirect result:', error.code, error.message);
});

// Initialize auth state listener
onAuthStateChanged(auth, (user) => {
  useAuthStore.getState().setUser(user);
});

